 1	import * as React from 'react';
 2	import { Form, FormGroup, FormHelperText, HelperText, HelperTextItem, TextInput } from '@patternfly/react-core';
 3	import { isValid } from 'utils/Common';
 4	import { isK8sGatewayHostValid } from '../../utils/IstioConfigUtils';
 5	
 6	type Props = {
 7	  k8sRouteHosts: string[];
 8	  onK8sRouteHostsChange: (valid: boolean, k8sRouteHosts: string[]) => void;
 9	  valid: boolean;
10	};
11	
12	export const K8sRouteHosts: React.FC<Props> = (props: Props) => {
13	  const isK8sRouteHostsValid = (k8sRouteHosts: string[]): boolean => {
14	    // All k8s route hosts must be valid
15	    return k8sRouteHosts.every(host => {
16	      return isK8sGatewayHostValid(host);
17	    });
18	  };
19	
20	  const k8sRouteHosts = props.k8sRouteHosts.length > 0 ? props.k8sRouteHosts.join(',') : '';
21	
22	  return (
23	    <Form isHorizontal={true}>
24	      <FormGroup label="K8s HTTPRoute Hosts" fieldId="advanced-k8sRouteHosts">
25	        <TextInput
26	          value={k8sRouteHosts}
27	          id="advanced-k8sRouteHosts"
28	          name="advanced-k8sRouteHosts"
29	          onChange={(_event, value) => {
30	            const k8sRouteHosts = value.split(',');
31	            const isValid = isK8sRouteHostsValid(k8sRouteHosts);
32	            props.onK8sRouteHostsChange(isValid, k8sRouteHosts);
33	          }}
34	          validated={isValid(props.valid)}
35	        />
36	        <FormHelperText>
37	          <HelperText>
38	            <HelperTextItem>
39	              {isValid(props.valid)
40	                ? 'The route hosts to which traffic is being sent. Enter one or multiple hosts separated by comma.'
41	                : "K8s Route hosts should be specified using FQDN format or '*.' format. IPs are not allowed."}
42	            </HelperTextItem>
43	          </HelperText>
44	        </FormHelperText>
45	      </FormGroup>
46	    </Form>
47	  );
48	};

